import {
  Card,
  CardAction,
  CardContent,
  CardFooter,
  CardHeader,
  CardTitle,
} from "./ui/card";

import Image from "next/image";
export default function LoginForm() {
  return (
    <div className="min-h-screen flex">
      <Image src="../public/icon.jpg" width={100} height={100} alt="App Icon" />
      <div className="w-1/2 flex items-center">
        <Card className="w-full h-full flex flex-col p-20">
          <CardHeader className="space-y-1 mt-10">
            <CardTitle className="text-2xl">Login to your account</CardTitle>
            <a href="#">Dont have an account? Sign up:</a>
          </CardHeader>

          <CardContent className="flex-1 flex flex-col mt-3">
            <form className="space-y-6">
              <div className="flex flex-col gap-3">
                <label htmlFor="email">Email</label>
                <input
                  id="email"
                  type="email"
                  placeholder="m@example.com"
                  required
                  className="p-4 h-8 rounded-xl border-2 border-gray-300"
                />
              </div>

              <div className="flex flex-col gap-3">
                <div className="flex items-center justify-between">
                  <label htmlFor="password">Password</label>
                  <a href="#" className="text-sm underline">
                    Forgot password?
                  </a>
                </div>
                <input
                  id="password"
                  type="password"
                  required
                  className="p-4 h-8 rounded-xl border-2 border-gray-300"
                />
              </div>

              <button
                type="submit"
                className="w-full bg-green-500 h-10 rounded-xl"
              >
                Login!
              </button>
            </form>
          </CardContent>

          <CardFooter>
            <div className="flex flex-col gap-3 w-full">
              <button type="submit" className="w-full">
                Login
              </button>
              <button type="button" className="w-full">
                Login with Google
              </button>
            </div>
          </CardFooter>
        </Card>
      </div>

      {/* Right half (optional visual area) */}
      <div className="w-1/2 bg-muted hidden md:block" />
    </div>
  );
}
